export default test({
	html: `
		<button>reset</button>
		<button>hello</button>
		<button>wheee</button>
		<p>pending</p>
	`,

	async test({ assert, target }) {
		const [reset, hello, wheee] = target.querySelectorAll('button');

		hello.click();
		await tick();
		assert.htmlEqual(
			target.innerHTML,
			`
				<button>reset</button>
				<button>hello</button>
				<button>wheee</button>
