11	export function SvelteBoundary(node, context) {
12		const props = b.object([]);
13	
14		for (const attribute of node.attributes) {
15			if (attribute.type !== 'Attribute' || attribute.value === true) {
16				// these can't exist, because they would have caused validation
17				// to fail, but typescript doesn't know that
18				continue;
19			}
20	
21			const chunk = Array.isArray(attribute.value)
22				? /** @type {AST.ExpressionTag} */ (attribute.value[0])
23				: attribute.value;
24	
25			const expression = /** @type {Expression} */ (context.visit(chunk.expression, context.state));
26	
27			if (chunk.metadata.expression.has_state) {
28				props.properties.push(b.get(attribute.name, [b.return(expression)]));
29			} else {
30				props.properties.push(b.init(attribute.name, expression));
31			}
32		}
33	
34		const nodes = [];
35	
36		/** @type {Statement[]} */
37		const const_tags = [];
38	
39		/** @type {Statement[]} */
40		const hoisted = [];
41	
42		let has_const = false;
43	
