import 'svelte/internal/flags/async';
import * as $ from 'svelte/internal/client';

var on_click = (_, deferred) => deferred.resolve('hello');
var root_1 = $.from_html(`<p></p>`);
var root_2 = $.from_html(`<p>pending</p>`);
var root_3 = $.from_html(` <!>`, 1);
var root = $.from_html(`<button>resolve</button> <!>`, 1);

export default function Main($$anchor) {
	let deferred = $.proxy(Promise.withResolvers());
	var fragment = root();
	var button = $.first_child(fragment);

	button.__click = [on_click, deferred];

	var node = $.sibling(button, 2);

	{
		const show = ($$anchor) => {
			var p = root_1();

			p.textContent = value;
			$.append($$anchor, p);
		};

		const pending = ($$anchor) => {
			var p_1 = root_2();

			$.append($$anchor, p_1);
		};

		$.boundary(node, { pending }, ($$anchor) => {
			$.next();

			var fragment_1 = root_3();
			var text = $.first_child(fragment_1);
			var node_1 = $.sibling(text);

			show(node_1);
			$.template_effect(($0) => $.set_text(text, `${$0 ?? ''} `), undefined, [() => deferred.promise]);
			$.append($$anchor, fragment_1);
		});
	}

	$.append($$anchor, fragment);
}

$.delegate(['click']);

