10	/**
11	 * Processes an array of template nodes, joining sibling text/expression nodes
12	 * (e.g. `{a} b {c}`) into a single update function. Along the way it creates
13	 * corresponding template node references these updates are applied to.
14	 * @param {AST.SvelteNode[]} nodes
15	 * @param {(is_text: boolean) => Expression} initial
16	 * @param {boolean} is_element
17	 * @param {ComponentContext} context
18	 */
19	export function process_children(nodes, initial, is_element, context) {
20		const within_bound_contenteditable = context.state.metadata.bound_contenteditable;
21		let prev = initial;
22		let skipped = 0;
23	
24		/** @typedef {Array<AST.Text | AST.ExpressionTag>} Sequence */
25		/** @type {Sequence} */
26		let sequence = [];
27	
28		/** @param {boolean} is_text */
29		function get_node(is_text) {
30			if (skipped === 0) {
31				return prev(is_text);
32			}
33	
34			return b.call(
35				'$.sibling',
36				prev(false),
37				(is_text || skipped !== 1) && b.literal(skipped),
38				is_text && b.true
39			);
40		}
41	
42		/**
43		 * @param {boolean} is_text
44		 * @param {string} name
45		 */
46		function flush_node(is_text, name) {
47			const expression = get_node(is_text);
48			let id = expression;
49	
50			if (id.type !== 'Identifier') {
51				id = b.id(context.state.scope.generate(name));
52				context.state.init.push(b.var(id, expression));
53			}
54	
55			prev = () => id;
56			skipped = 1; // the next node is `$.sibling(id)`
57	
58			return id;
59		}
60	
61		/**
62		 * @param {Sequence} sequence
63		 */
64		function flush_sequence(sequence) {
65			if (sequence.every((node) => node.type === 'Text')) {
66				skipped += 1;
67				context.state.template.push_text(sequence);
68				return;
69			}
70	
71			context.state.template.push_text([{ type: 'Text', data: ' ', raw: ' ', start: -1, end: -1 }]);
72	
73			const { has_state, value } = build_template_chunk(sequence, context);
74	
75			// if this is a standalone `{expression}`, make sure we handle the case where
76			// no text node was created because the expression was empty during SSR
77			const is_text = sequence.length === 1;
78			const id = flush_node(is_text, 'text');
79	
80			const update = b.stmt(b.call('$.set_text', id, value));
81	
82			if (has_state && !within_bound_contenteditable) {
83				context.state.update.push(update);
84			} else {
85				context.state.init.push(b.stmt(b.assignment('=', b.member(id, 'nodeValue'), value)));
86			}
87		}
88	
89		for (const node of nodes) {
90			if (node.type === 'Text' || node.type === 'ExpressionTag') {
91				sequence.push(node);
92			} else {
93				if (sequence.length > 0) {
94					flush_sequence(sequence);
95					sequence = [];
96				}
97	
98				let child_state = context.state;
99	
100				if (is_static_element(node, context.state)) {
101					skipped += 1;
102				} else if (node.type === 'EachBlock' && nodes.length === 1 && is_element) {
103					node.metadata.is_controlled = true;
104				} else {
105					const id = flush_node(false, node.type === 'RegularElement' ? node.name : 'node');
106					child_state = { ...context.state, node: id };
107				}
108	
109				context.visit(node, child_state);
110			}
111		}
112	
113		if (sequence.length > 0) {
114			flush_sequence(sequence);
115		}
116	
117		// if there are trailing static text nodes/elements,
118		// traverse to the last (n - 1) one when hydrating
119		if (skipped > 1) {
120			skipped -= 1;
121			context.state.init.push(b.stmt(b.call('$.next', skipped !== 1 && b.literal(skipped))));
122		}
123	}
